import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "file.txt"; // User input containing only the file name (without directory traversal)

        String baseDirectory = "/path/to/secure/directory/";
        String sanitizedPath = new File(baseDirectory, userInput).getCanonicalPath(); // Construct full path and get canonical path

        if (!sanitizedPath.startsWith(baseDirectory)) {
            System.out.println("Invalid file path specified.");
            return;
        }

        try {
            File file = new File(sanitizedPath);
            FileInputStream fis = new FileInputStream(file);

            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }

            fis.close();
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

